import { describe, expect, it, vi } from "vitest";
import { extractFirstTraceId, parseWaitForTraceArgs, pollForFirstTrace, } from "./waitForTrace.js";
const baseConfig = {
    serviceUrl: "https://bitfab.test",
    apiKey: "test-key",
    verbose: false,
    debug: false,
    sessionLogConsent: null,
};
function fakeProxy(responses) {
    let call = 0;
    return {
        toolCall: vi.fn(async () => {
            const res = responses[Math.min(call, responses.length - 1)];
            call += 1;
            return {
                content: [{ type: "text", text: res.text }],
                isError: res.isError ?? false,
            };
        }),
    };
}
describe("extractFirstTraceId", () => {
    it("returns null when the server reports no matches", () => {
        expect(extractFirstTraceId("No traces found matching the filter criteria.")).toBeNull();
    });
    it("extracts the first UUID from a 'Found N traces' response", () => {
        const text = [
            "Found 2 traces:",
            "",
            "ID: 11111111-2222-3333-4444-555555555555",
            "  Status: completed",
            "",
            "ID: aaaaaaaa-bbbb-cccc-dddd-eeeeeeeeeeee",
        ].join("\n");
        expect(extractFirstTraceId(text)).toBe("11111111-2222-3333-4444-555555555555");
    });
    it("returns null for unrelated text", () => {
        expect(extractFirstTraceId("some random text without an ID")).toBeNull();
    });
});
describe("parseWaitForTraceArgs", () => {
    it("returns defaults when only the key is provided", () => {
        const args = parseWaitForTraceArgs(["my-key"]);
        expect(args.traceFunctionKey).toBe("my-key");
        expect(args.timeoutMs).toBe(10 * 60 * 1000);
        expect(args.pollIntervalMs).toBe(10_000);
    });
    it("overrides timeout + poll interval via flags", () => {
        const args = parseWaitForTraceArgs([
            "my-key",
            "--timeout-ms",
            "5000",
            "--poll-interval-ms",
            "500",
        ]);
        expect(args.timeoutMs).toBe(5000);
        expect(args.pollIntervalMs).toBe(500);
    });
    it("exits when the key is missing", () => {
        const mockExit = vi
            .spyOn(process, "exit")
            .mockImplementation(() => undefined);
        const mockError = vi.spyOn(console, "error").mockImplementation(() => { });
        parseWaitForTraceArgs([]);
        expect(mockExit).toHaveBeenCalledWith(1);
        expect(mockError).toHaveBeenCalledWith(expect.stringContaining("Usage:"));
        mockExit.mockRestore();
        mockError.mockRestore();
    });
    it("exits when the first arg looks like a flag", () => {
        const mockExit = vi
            .spyOn(process, "exit")
            .mockImplementation(() => undefined);
        const mockError = vi.spyOn(console, "error").mockImplementation(() => { });
        parseWaitForTraceArgs(["--timeout-ms", "1000"]);
        expect(mockExit).toHaveBeenCalledWith(1);
        expect(mockError).toHaveBeenCalledWith(expect.stringContaining("Usage:"));
        mockExit.mockRestore();
        mockError.mockRestore();
    });
    it("exits for malformed numeric flag values", () => {
        const mockExit = vi
            .spyOn(process, "exit")
            .mockImplementation(() => undefined);
        const mockError = vi.spyOn(console, "error").mockImplementation(() => { });
        parseWaitForTraceArgs(["key", "--timeout-ms", "abc"]);
        expect(mockExit).toHaveBeenCalledWith(1);
        expect(mockError).toHaveBeenCalledWith(expect.stringContaining("not a valid positive number"));
        mockExit.mockRestore();
        mockError.mockRestore();
    });
});
describe("pollForFirstTrace", () => {
    it("returns status=found with trace ID + dashboard URL on first hit", async () => {
        const proxy = fakeProxy([
            { text: "No traces found matching the filter criteria." },
            {
                text: [
                    "Found 1 traces:",
                    "",
                    "ID: 11111111-2222-3333-4444-555555555555",
                    "  Status: completed",
                ].join("\n"),
            },
        ]);
        const result = await pollForFirstTrace({
            proxy,
            config: baseConfig,
            traceFunctionKey: "my-fn",
            timeoutMs: 5000,
            pollIntervalMs: 10,
        });
        expect(result.status).toBe("found");
        if (result.status === "found") {
            expect(result.traceId).toBe("11111111-2222-3333-4444-555555555555");
            expect(result.url).toBe("https://bitfab.test/traces/11111111-2222-3333-4444-555555555555");
        }
        expect(proxy.toolCall).toHaveBeenCalledTimes(2);
    });
    it("strips a trailing slash from serviceUrl when constructing the dashboard URL", async () => {
        const proxy = fakeProxy([
            {
                text: "Found 1 traces:\n\nID: 11111111-2222-3333-4444-555555555555",
            },
        ]);
        const result = await pollForFirstTrace({
            proxy,
            config: { ...baseConfig, serviceUrl: "https://bitfab.test/" },
            traceFunctionKey: "my-fn",
            timeoutMs: 5000,
            pollIntervalMs: 10,
        });
        expect(result.status).toBe("found");
        if (result.status === "found") {
            expect(result.url).toBe("https://bitfab.test/traces/11111111-2222-3333-4444-555555555555");
        }
    });
    it("returns status=timeout when no trace arrives before the deadline", async () => {
        const proxy = fakeProxy([{ text: "No traces found" }]);
        const result = await pollForFirstTrace({
            proxy,
            config: baseConfig,
            traceFunctionKey: "my-fn",
            timeoutMs: 300,
            pollIntervalMs: 50,
        });
        expect(result.status).toBe("timeout");
        if (result.status === "timeout") {
            expect(result.waitedMs).toBeGreaterThanOrEqual(300);
        }
    });
    it("returns status=interrupted when isInterrupted flips to true", async () => {
        const proxy = fakeProxy([{ text: "No traces found" }]);
        let tripped = false;
        // Trip the interrupt after the first poll so the sleep loop observes it.
        setTimeout(() => {
            tripped = true;
        }, 30);
        const result = await pollForFirstTrace({
            proxy,
            config: baseConfig,
            traceFunctionKey: "my-fn",
            timeoutMs: 5000,
            pollIntervalMs: 1000,
            isInterrupted: () => tripped,
        });
        expect(result.status).toBe("interrupted");
    });
    it("returns status=error when the MCP proxy surfaces an error", async () => {
        const proxy = fakeProxy([
            { text: "Not authenticated. Run /bitfab:setup login.", isError: true },
        ]);
        const result = await pollForFirstTrace({
            proxy,
            config: baseConfig,
            traceFunctionKey: "my-fn",
            timeoutMs: 5000,
            pollIntervalMs: 10,
        });
        expect(result.status).toBe("error");
        if (result.status === "error") {
            expect(result.message).toContain("Not authenticated");
        }
    });
});
